static inline float SL7_ftube(int t, float v){
  float x=(v-SL7_VMIN)*((SL7_N-1)/(SL7_VMAX-SL7_VMIN));
  if(x<=0)x=0; if(x>=SL7_N-1)x=SL7_N-1.001f;
  int i=(int)x; float fr=x-i; const float*T=(t?SL7_FT1:SL7_FT0);
  return T[i]+fr*(T[i+1]-T[i]);
}
